               @bind="searchTerm" @bind:event="oninput" @onkeyup="OnSearchKeyUp" />
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="LoadShipments">Search</button>
    </div>
</div>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (shipments is not null)
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Update Status</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in shipments)
                {
                    <tr>
                        <td><strong>@s.TrackingNumber</strong></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td><span class="badge @GetBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width:auto;display:inline-block"
                                    value="@((int)s.Status)"
                                    @onchange="(e) => OnStatusChanged(s, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@((int)status)">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private bool loading = true;
    private string? statusFilter;
    private string? searchTerm;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        shipments = await ShipmentService.GetShipmentsAsync(statusFilter, searchTerm);
        loading = false;
    }

    private async Task OnStatusFilterChanged(ChangeEventArgs e)
    {
        statusFilter = e.Value?.ToString();
        await LoadShipments();
    }

    private async Task OnSearchKeyUp(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await LoadShipments();
    }

    private async Task OnStatusChanged(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, (ShipmentStatus)newStatus);
            shipment.Status = (ShipmentStatus)newStatus;
        }
    }

    private static string GetBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1 class="mb-4">🔍 Track a Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number (e.g., TRK-20240101)"
                   @bind="trackingNumber" @onkeyup="OnKeyUp" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@loading">
                @if (loading)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null && !loading)
{
    <div class="alert alert-warning">
        <strong>Shipment not found.</strong> Please check the tracking number and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card shadow-sm" style="max-width: 600px;">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@shipment.TrackingNumber</strong>
            <span class="badge @GetBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row mb-2">
                <div class="col-5 text-muted">Description</div>
                <div class="col-7">@shipment.Description</div>
            </div>
            <div class="row mb-2">
                <div class="col-5 text-muted">Recipient</div>
                <div class="col-7">@shipment.RecipientName</div>
            </div>
            <hr />
            <div class="row mb-2">
                <div class="col-5 text-muted">Origin</div>
                <div class="col-7">@shipment.Origin</div>
            </div>
            <div class="row mb-2">
                <div class="col-5 text-muted">Destination</div>
                <div class="col-7">@shipment.Destination</div>
            </div>
            <hr />
            <div class="row mb-2">
                <div class="col-5 text-muted">Created</div>
                <div class="col-7">@shipment.CreatedDate.ToString("MMM dd, yyyy")</div>
            </div>
            <div class="row mb-2">
                <div class="col-5 text-muted">Estimated Delivery</div>
                <div class="col-7">@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</div>
            </div>
            @if (shipment.ActualDelivery.HasValue)
            {
                <div class="row mb-2">
                    <div class="col-5 text-muted">Actual Delivery</div>
                    <div class="col-7 text-success fw-bold">@shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</div>
                </div>
            }
        </div>
    </div>
}

