 @page "/shipments"
 @using Microsoft.AspNetCore.Authorization
 @using ShipmentTracker.Client.Models
 @using ShipmentTracker.Client.Services
 @attribute [Authorize]
 @inject IShipmentService ShipmentService

 <PageTitle>Dispatch Dashboard</PageTitle>

 <h1 class="mb-4">🚚 Dispatch Dashboard</h1>

 <div class="row mb-3 g-2">
     <div class="col-md-4">
         <label class="form-label">Filter by Status</label>
         <select class="form-select" @onchange="OnStatusFilterChanged">
             <option value="">All</option>
             @foreach (var status in Enum.GetValues<ShipmentStatus>())
             {
                 <option value="@status">@status</option>
             }
         </select>
     </div>
     <div class="col-md-4">
         <label class="form-label">Search</label>
         <input class="form-control" placeholder="Tracking #, destination, or recipient"
                @bind="searchTerm" @bind:event="oninput" @onkeyup="OnSearchKeyUp" />
     </div>
     <div class="col-md-4 d-flex align-items-end">
         <button class="btn btn-primary" @onclick="LoadShipments">Search</button>
     </div>
 </div>

 @if (loading)
 {
     <div class="d-flex justify-content-center my-5">
         <div class="spinner-border text-primary" role="status">
             <span class="visually-hidden">Loading...</span>
         </div>
     </div>
 }
 else if (shipments is not null)
 {
     <div class="table-responsive">
         <table class="table table-striped table-hover">
             <thead class="table-dark">
                 <tr>
                     <th>Tracking #</th>
                     <th>Origin</th>
                     <th>Destination</th>
                     <th>Status</th>
                     <th>Est. Delivery</th>
                     <th>Update Status</th>
                 </tr>
             </thead>
             <tbody>
                 @foreach (var s in shipments)
                 {
                     <tr>
                         <td><strong>@s.TrackingNumber</strong></td>
                         <td>@s.Origin</td>
                         <td>@s.Destination</td>
                         <td><span class="badge @GetBadgeClass(s.Status)">@s.Status</span></td>
                         <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                         <td>
                             <select class="form-select form-select-sm" style="width:auto;display:inline-block"
                                     value="@((int)s.Status)"
                                     @onchange="(e) => OnStatusChanged(s, e)">
                                 @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                 {
                                     <option value="@((int)status)">@status</option>
                                 }
                             </select>
                         </td>
                     </tr>
                 }
             </tbody>
         </table>
     </div>
 }

 @code {
     private List<ShipmentDto>? shipments;
     private bool loading = true;
     private string? statusFilter;
     private string? searchTerm;

     protected override async Task OnInitializedAsync()
     {
         await LoadShipments();
     }

     private async Task LoadShipments()
     {
         loading = true;
         shipments = await ShipmentService.GetShipmentsAsync(statusFilter, searchTerm);
         loading = false;
     }

     private async Task OnStatusFilterChanged(ChangeEventArgs e)
     {
         statusFilter = e.Value?.ToString();
         await LoadShipments();
     }

     private async Task OnSearchKeyUp(KeyboardEventArgs e)
     {
         if (e.Key == "Enter")
             await LoadShipments();
     }

     private async Task OnStatusChanged(ShipmentDto shipment, ChangeEventArgs e)
     {
         if (int.TryParse(e.Value?.ToString(), out var newStatus))
         {
             await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, (ShipmentStatus)newStatus);
             shipment.Status = (ShipmentStatus)newStatus;
         }
     }

     private static string GetBadgeClass(ShipmentStatus status) => status switch
     {
         ShipmentStatus.Pending => "bg-secondary",
         ShipmentStatus.PickedUp => "bg-info text-dark",
         ShipmentStatus.InTransit => "bg-primary",
         ShipmentStatus.OutForDelivery => "bg-warning text-dark",
         ShipmentStatus.Delivered => "bg-success",
         ShipmentStatus.Cancelled => "bg-danger",
         _ => "bg-secondary"
     };
 }

