                     <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                 }
                 Track
             </button>
         </div>
     </div>
 </div>

 @if (searched && shipment is null && !loading)
 {
     <div class="alert alert-warning">
         <strong>Shipment not found.</strong> Please check the tracking number and try again.
     </div>
 }

 @if (shipment is not null)
 {
     <div class="card shadow-sm" style="max-width: 600px;">
         <div class="card-header d-flex justify-content-between align-items-center">
             <strong>@shipment.TrackingNumber</strong>
             <span class="badge @GetBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
         </div>
         <div class="card-body">
             <div class="row mb-2">
                 <div class="col-5 text-muted">Description</div>
                 <div class="col-7">@shipment.Description</div>
             </div>
             <div class="row mb-2">
                 <div class="col-5 text-muted">Recipient</div>
                 <div class="col-7">@shipment.RecipientName</div>
             </div>
             <hr />
             <div class="row mb-2">
                 <div class="col-5 text-muted">Origin</div>
                 <div class="col-7">@shipment.Origin</div>
             </div>
             <div class="row mb-2">
                 <div class="col-5 text-muted">Destination</div>
                 <div class="col-7">@shipment.Destination</div>
             </div>
             <hr />
             <div class="row mb-2">
                 <div class="col-5 text-muted">Created</div>
                 <div class="col-7">@shipment.CreatedDate.ToString("MMM dd, yyyy")</div>
             </div>
             <div class="row mb-2">
                 <div class="col-5 text-muted">Estimated Delivery</div>
                 <div class="col-7">@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</div>
             </div>
             @if (shipment.ActualDelivery.HasValue)
             {
                 <div class="row mb-2">
                     <div class="col-5 text-muted">Actual Delivery</div>
                     <div class="col-7 text-success fw-bold">@shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</div>
                 </div>
             }
         </div>
     </div>
 }

 @code {
     private string? trackingNumber;
     private ShipmentDto? shipment;
     private bool loading;
     private bool searched;

     private async Task DoTrackShipment()
     {
         if (string.IsNullOrWhiteSpace(trackingNumber))
             return;

         loading = true;
         searched = true;
         shipment = null;
         shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
         loading = false;
     }

     private async Task OnKeyUp(KeyboardEventArgs e)
     {
         if (e.Key == "Enter")
             await DoTrackShipment();
     }

     private static string GetBadgeClass(ShipmentStatus status) => status switch
     {
         ShipmentStatus.Pending => "bg-secondary",
         ShipmentStatus.PickedUp => "bg-info text-dark",
         ShipmentStatus.InTransit => "bg-primary",
         ShipmentStatus.OutForDelivery => "bg-warning text-dark",
         ShipmentStatus.Delivered => "bg-success",
         ShipmentStatus.Cancelled => "bg-danger",
         _ => "bg-secondary"
     };
 }

